sql_query:
SELECT "Name of ICI"
FROM clinical_trials
WHERE "Cancer type" = 'Prostate';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Name of ICI" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Prostate'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_ici_class(source_value) AS "class"
FROM base;
